const item = $input.item.json;

let raw = '';
if (item.content && Array.isArray(item.content.parts) && item.content.parts[0] && item.content.parts[0].text) {
  raw = item.content.parts[0].text;
} else if (typeof item.content === 'string') {
  raw = item.content;
} else if (typeof item.text === 'string') {
  raw = item.text;
} else if (typeof item.data === 'string') {
  raw = item.data;
}

let parsed;
try {
  const cleaned = String(raw).replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { type: 'OTHER', product_name: null, price_rmb: null, confidence: 0 };
}

return [{ json: { ...item, classification: parsed } }];

const c = $json.classification || {};
const parts = [];
parts.push('[Dari screenshot produk] Saya mau tanya/order barang ini');
if (c.product_name) parts.push(`nama: ${c.product_name}`);
if (c.price_rmb) parts.push(`harga: ${c.price_rmb} RMB`);
parts.push('Tolong bantu hitungkan estimasi totalnya ya (boleh ditanya dulu kalau ada info lain yang masih kurang).');

return [{
  json: {
    ...$json,
    ai_input_text: parts.join(', ')
  }
}];
